DELETE FROM vso_sale_model t
WHERE t.id IN

    #{id}

mapper.select:
SELECT 
FROM vso_sale_model t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.sale_code = #{saleModelCode}


    AND t.model_name = #{modelName}


    AND t.variant_code = #{variantCode}


    AND t.parameters = #{parameters}


    AND t.images = #{images}


    AND t.earnest_money = #{earnestMoney}


    AND t.earnest_money_price = #{earnestMoneyPrice}


    AND t.down_payment = #{downPayment}


    AND t.down_payment_price = #{downPaymentPrice}


    AND t.enable = #{enable}


    AND t.sort = #{sort}


    AND t.base_price = #{basePrice}


    AND t.listing_status = #{listingStatus}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC

SELECT 
FROM vso_sale_model t
WHERE t.row_valid = 1

    AND t.sale_code = #{saleModelCode}


    AND t.model_name LIKE #{modelName}


    AND t.variant_code = #{variantCode}


    and date_format(t.create_time,'%Y%m%d') >= date_format(#{beginTime},'%Y%m%d')


    and date_format(t.create_time,'%Y%m%d') <= date_format(#{endTime},'%Y%m%d')

ORDER BY t.sort ASC, t.id DESC

SELECT COUNT(*)
FROM vso_sale_model t
WHERE t.row_valid = 1

    AND t.sale_code = #{saleModelCode}


    AND t.model_name LIKE #{modelName}
